from dataclasses import dataclass

MODEL_LIMITS = {
    "claude-haiku-4-5-20251001": 200_000,
    "claude-sonnet-4-6": 200_000,
}

@dataclass
class TokenBudget:
    model: str
    system_reserve: int = 1_000    # system prompt + overhead
    tools_reserve: int = 2_000     # tool definitions
    response_reserve: int = 2_000  # max_tokens for the reply

    @property
    def context_limit(self) -> int:
        return MODEL_LIMITS[self.model]

    @property
    def available_for_context(self) -> int:
        """Tokens available for messages + retrieved documents."""
        return (
            self.context_limit
            - self.system_reserve
            - self.tools_reserve
            - self.response_reserve
        )

    @property
    def max_window_tokens(self) -> int:
        return self.available_for_context // 2   # half for window

    @property
    def max_retrieval_tokens(self) -> int:
        return self.available_for_context // 2   # half for RAG

BUDGET = TokenBudget(model="claude-haiku-4-5-20251001")
print(f"Available for context: {BUDGET.available_for_context:,}")
print(f"Max window: {BUDGET.max_window_tokens:,}")
print(f"Max retrieval: {BUDGET.max_retrieval_tokens:,}")
